use alloc::vec::Vec;

// Generated by a build script into OUT_DIR.
// Contains DEFLATE-compressed Limine binaries used by the installer.
mod generated {
    include!(concat!(env!("OUT_DIR"), "/install_payload.rs"));
}

fn decode_deflate(data: &[u8], expected_len: usize) -> Vec<u8> {
    let out = miniz_oxide::inflate::decompress_to_vec_with_limit(data, expected_len)
        .expect("install payload DEFLATE decode failed");
    if out.len() != expected_len {
        panic!(
            "install payload length mismatch (expected {}, got {})",
            expected_len,
            out.len()
        );
    }
    out
}

pub fn limine_bios_sys() -> Vec<u8> {
    decode_deflate(generated::LIMINE_BIOS_SYS_DEFLATE, generated::LIMINE_BIOS_SYS_LEN)
}

pub fn limine_bios_hdd_bin() -> Vec<u8> {
    decode_deflate(
        generated::LIMINE_BIOS_HDD_BIN_DEFLATE,
        generated::LIMINE_BIOS_HDD_BIN_LEN,
    )
}
